import{_ as a,c as e,o as r,a1 as d}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"플랫폼 통합: 다양한 프로토콜 연결 | Antigravity-Manager","description":"Antigravity Tools의 플랫폼 프로토콜 연결 방법을 학습합니다. OpenAI, Anthropic, Gemini 등 7가지 프로토콜의 통합 API 게이트웨이 변환을 지원합니다.","frontmatter":{"title":"플랫폼 통합: 다양한 프로토콜 연결 | Antigravity-Manager","sidebarTitle":"AI 플랫폼 연결","subtitle":"플랫폼 통합: 다양한 프로토콜 연결","description":"Antigravity Tools의 플랫폼 프로토콜 연결 방법을 학습합니다. OpenAI, Anthropic, Gemini 등 7가지 프로토콜의 통합 API 게이트웨이 변환을 지원합니다.","order":200},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/platforms/index.md"}'),o={name:"ko/lbjlaq/Antigravity-Manager/platforms/index.md"};function i(l,t,n,s,c,h){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="플랫폼-및-통합" tabindex="-1">플랫폼 및 통합 <a class="header-anchor" href="#플랫폼-및-통합" aria-label="Permalink to &quot;플랫폼 및 통합&quot;">​</a></h1><p>Antigravity Tools의 핵심 능력은 여러 AI 플랫폼의 프로토콜을 통합 로컬 API 게이트웨이로 변환하는 것입니다. 이 장에서는 각 프로토콜의 연결 방식, 호환 경계 및 모범 사례를 상세히 소개합니다.</p><h2 id="이-장에-포함된-내용" tabindex="-1">이 장에 포함된 내용 <a class="header-anchor" href="#이-장에-포함된-내용" aria-label="Permalink to &quot;이 장에 포함된 내용&quot;">​</a></h2><table tabindex="0"><thead><tr><th>튜토리얼</th><th>설명</th></tr></thead><tbody><tr><td><a href="./openai/">OpenAI 호환 API</a></td><td><code>/v1/chat/completions</code> 및 <code>/v1/responses</code>의 구현 전략으로 OpenAI SDK 무감각 연결</td></tr><tr><td><a href="./anthropic/">Anthropic 호환 API</a></td><td><code>/v1/messages</code> 및 Claude Code의 핵심 계약으로 사고 체인, 시스템 프롬프트 등 핵심 능력 지원</td></tr><tr><td><a href="./gemini/">Gemini 네이티브 API</a></td><td><code>/v1beta/models</code> 및 Google SDK 엔드포인트 연결로 <code>x-goog-api-key</code> 호환 지원</td></tr><tr><td><a href="./imagen/">Imagen 3 이미지 생성</a></td><td>OpenAI Images 매개변수 <code>size</code>/<code>quality</code> 자동 매핑으로 임의 가로세로 비율 지원</td></tr><tr><td><a href="./audio/">오디오 변환</a></td><td><code>/v1/audio/transcriptions</code>의 제한 및 대용량 본문 처리</td></tr><tr><td><a href="./mcp/">MCP 엔드포인트</a></td><td>Web Search/Reader/Vision을 호출 가능한 도구로 노출</td></tr><tr><td><a href="./cloudflared/">Cloudflared 터널</a></td><td>로컬 API를 공개 네트워크에 안전하게 노출하는 원클릭(기본적으로 안전하지 않음)</td></tr></tbody></table><h2 id="학습-경로-추천" tabindex="-1">학습 경로 추천 <a class="header-anchor" href="#학습-경로-추천" aria-label="Permalink to &quot;학습 경로 추천&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">추천 순서</p><ol><li><strong>먼저 사용할 프로토콜 학습</strong>: Claude Code를 사용하면 먼저 <a href="./anthropic/">Anthropic 호환 API</a> 보기. OpenAI SDK를 사용하면 먼저 <a href="./openai/">OpenAI 호환 API</a> 보기</li><li><strong>그다음 Gemini 네이티브 학습</strong>: Google SDK 직접 연결 방법 이해</li><li><strong>필요에 따라 확장 기능 학습</strong>: 이미지 생성, 오디오 변환, MCP 도구</li><li><strong>마지막으로 터널 학습</strong>: 공개 네트워크 노출이 필요할 때만 <a href="./cloudflared/">Cloudflared 터널</a> 보기</li></ol></div><p><strong>빠른 선택</strong>:</p><table tabindex="0"><thead><tr><th>시나리오</th><th>먼저 볼 것</th></tr></thead><tbody><tr><td>Claude Code CLI 사용</td><td><a href="./anthropic/">Anthropic 호환 API</a></td></tr><tr><td>OpenAI Python SDK 사용</td><td><a href="./openai/">OpenAI 호환 API</a></td></tr><tr><td>Google 공식 SDK 사용</td><td><a href="./gemini/">Gemini 네이티브 API</a></td></tr><tr><td>AI 이미지 그리기 필요</td><td><a href="./imagen/">Imagen 3 이미지 생성</a></td></tr><tr><td>음성을 텍스트로 변환 필요</td><td><a href="./audio/">오디오 변환</a></td></tr><tr><td>인터넷 검색/웹 읽기 필요</td><td><a href="./mcp/">MCP 엔드포인트</a></td></tr><tr><td>원격 액세스 필요</td><td><a href="./cloudflared/">Cloudflared 터널</a></td></tr></tbody></table><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">시작 전 확인</p><ul><li><a href="./../start/installation/">설치 및 업그레이드</a> 완료</li><li><a href="./../start/add-account/">계정 추가</a> 완료</li><li><a href="./../start/proxy-and-first-client/">로컬 리버스 프록시 시작</a> 완료(최소 <code>/healthz</code> 액세스 가능)</li></ul></div><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 학습한 후 다음을 계속 학습할 수 있습니다:</p><ul><li><a href="./../advanced/">고급 구성</a>: 모델 라우팅, 할당량 거버넌스, 고가용성 스케줄링 등 고급 기능</li><li><a href="./../faq/">일반적인 문제</a>: 401/404/429 등 오류 발생 시 문제 해결 가이드</li></ul>',13)])])}const A=a(o,[["render",i]]);export{f as __pageData,A as default};
